solution: ```class Solution {
public:
    int superEggDrop(int k, int n) {
        vector<int> dp(k + 1, 0);
        int moves = 0;
        while (dp[k] < n) {
            for (int eggs = k; eggs >= 1; --eggs) {
                dp[eggs] = dp[eggs] + dp[eggs - 1] + 1;
            }
            ++moves;
        }
        return moves;
    }
};
```
